############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("FiniteSolutionSets"); Context()->variables->are(z=>'Real'); $solution = Formula("{23}");
############################################################ # Body ############################################################
BEGIN_PGML Solve for [`z`] in [`-\frac{2}{5}z-\frac{3}{2}=-\frac{1}{2}z+\frac{4}{5}\text{.}`]
[_]{$solution}{20}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION With fractions present, we decide to identify the LCD. The denominators are [`2`] and [`5\text{,}`] so the LCD is [`10\text{.}`] And so our first algebra step is to multiply each side of the equation by [`10\text{:}`]
[```\newcommand{\multiplyleft}[2][\cdot]{{\highlight{{#2#1{}}}}}\newcommand{\amp}{&} \begin{aligned} -\frac{2}{5}z-\frac{3}{2}\amp=-\frac{1}{2}z+\frac{4}{5}\\ \multiplyleft{10}\left(-\frac{2}{5}z-\frac{3}{2}\right)\amp=\multiplyleft{10}\left(-\frac{1}{2}z+\frac{4}{5}\right)\\ 10\left(-\frac{2}{5}z\right)-10\left(\frac{3}{2}\right)\amp=10\left(-\frac{1}{2}z\right)+10\left(\frac{4}{5}\right)\\ -4z-15\amp=-5z+8\\ z-15\amp=8\\ z\amp=23 \end{aligned} ```]
Checking the solution [`23\text{:}`]
[```\newcommand{\substitute}[1]{{\color{blue}{{#1}}}}\newcommand{\confirm}[1]{\stackrel{\checkmark}{#1}}\newcommand{\wonder}[1]{\stackrel{\text{?}}{#1}}\newcommand{\amp}{&} \begin{aligned} -\frac{2}{5}z-\frac{3}{2}\amp=-\frac{1}{2}z+\frac{4}{5}\\ -\frac{2}{5}(\substitute{23})-\frac{3}{2}\amp\wonder{=}-\frac{1}{2}(\substitute{23})+\frac{4}{5}\\ -\frac{46}{5}-\frac{3}{2}\amp\wonder{=}-\frac{23}{2}+\frac{4}{5}\\ -\frac{92}{10}-\frac{15}{10}\amp\wonder{=}-\frac{115}{10}+\frac{8}{10}\\ -\frac{107}{10}\amp\confirm{=}-\frac{107}{10} \end{aligned} ```]
So the solution is [`23`] and so the solution set is [`\{23\}\text{.}`]
END_PGML_SOLUTION
